SELECT MIN(Rate) AS MinimumHourlyRate
FROM pay_rates
WHERE Currency = 'USD';

SELECT Rate
FROM pay_rates
WHERE PayFrequency = '1' AND Currency = 'USD';

SELECT Rate
FROM pay_rates
WHERE BusinessEntityID = 1;

SELECT COUNT(*) 
FROM pay_rates 
WHERE RateChangeDate LIKE '2023%';

SELECT MAX(Rate) AS MaxSalaryRate
FROM pay_rates
WHERE Currency = 'USD';

SELECT StartDate, EndDate, NumberOfDays
FROM employee_leaves
WHERE StartDate >= '2023-06-01' AND EndDate <= '2023-06-30';

SELECT BusinessEntityID, StartDate
FROM employee_positions
WHERE EndDate IS NULL;
